         const filtro = {} as FilterProCDA; 
  
              const filtroMem = sessionStorage.getItem(btoa('ProCDAFilter')) ? JSON.parse(atob(sessionStorage.getItem(btoa('ProCDAFilter')) ?? '') || '{}') : {} as FilterProCDA;
            setWindowFilter(filtroMem);              
